}

// NewSpawnFormOverlay creates a form overlay with name, branch (optional), and path (optional) inputs.
func NewSpawnFormOverlay(title string, width int) *FormOverlay {
	f := &FormOverlay{
		title:     title,
		width:     width,
		fieldKeys: []string{"name", "branch", "path"},
	}

