		return true

	case tea.KeyTab, tea.KeyDown:
		focused := f.focusedKey()
		if len(f.fieldKeys) > 0 && focused == f.fieldKeys[len(f.fieldKeys)-1] {
			for i := 0; i < len(f.fieldKeys)-1; i++ {
				f.updateForm(huh.PrevField())
			}
			return false
		}
		f.updateForm(huh.NextField())
